BEGIN TRANSACTION;
CREATE TABLE account_chats (
    account_id INTEGER NOT NULL,
    chat_id    INTEGER NOT NULL,
    can_write  TEXT,
    joined_at  TEXT DEFAULT (datetime('now')),
    UNIQUE(account_id, chat_id)
);
CREATE TABLE accounts (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    label       TEXT,                      -- ярлык: «Вася SDR», «Аккаунт #2»
    phone       TEXT,                      -- номер телефона аккаунта
    username    TEXT,                      -- @username
    role        TEXT,                      -- роль в команде: sdr|qualifier|closer|scheduler
    status      TEXT DEFAULT 'active',     -- active|warming|paused|banned
    daily_limit INTEGER DEFAULT 15,        -- лимит первых сообщений в день
    notes       TEXT,
    created_at  TEXT DEFAULT (datetime('now')), tg_session TEXT, wa_authed TEXT, proxy TEXT, warm_stage INTEGER DEFAULT 0, warm_started_at TEXT, last_warm_at TEXT, spam_status TEXT, spam_checked_at TEXT, avatar TEXT, description TEXT, api_id INTEGER, api_hash TEXT, protected INTEGER DEFAULT 0, chats_backup TEXT, kind TEXT, country TEXT, bought_at TEXT, tg_name TEXT, proxy_alive INTEGER, proxy_checked_at TEXT, session_alive INTEGER, session_state TEXT, session_reason TEXT, session_checked_at TEXT, tg_2fa TEXT, tg_2fa_set_at TEXT, reg_source TEXT, reg_activation_id TEXT, reg_cost REAL, protect_stage TEXT, protect_phone_activation_id TEXT, protect_last_try_at TEXT, protect_note TEXT,
    UNIQUE(phone)
);
CREATE TABLE ai_agents (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    name        TEXT,
    task        TEXT,                          -- leadgen|networking|inviting|qualify|support|other
    prompt      TEXT,                          -- характер/инструкция агента
    account_id  INTEGER,                       -- аккаунт-исполнитель (accounts.id), опц.
    active      INTEGER DEFAULT 1,
    created_at  TEXT DEFAULT (datetime('now'))
);
Твоя задача: выходить на агентства недвижимости и договариваться о встрече (КЭВ).

Правила ведения диалога:
1. Первое касание — коротко, по делу: кто ты, откуда, что предлагаешь
2. После ответа — поддерживай диалог, отвечай на вопросы
3. Цель — назначить Zoom-встречу на 20 минут
4. Если не отвечают 5+ дней — одно вежливое напоминание
5. Никакого спама, не больше 2 сообщений без ответа
6. Тон — деловой, дружелюбный, уважительный

Ключевое предложение: помогаем агентствам закрывать сорвавшиеся сделки с ипотекой — выдаём заём под залог недвижимости, когда банк отказал. Быстро, до 20 млн, под 18% годовых.',NULL,1,'2026-07-20 00:18:17');
CREATE TABLE app_settings (
    key   TEXT PRIMARY KEY,
    value TEXT
);
CREATE TABLE campaign_accounts (
    campaign_id INTEGER NOT NULL,
    account_id  INTEGER NOT NULL,
    daily_limit INTEGER,                    -- персональный лимит агента (пусто = лимит кампании)
    UNIQUE(campaign_id, account_id)
);
CREATE TABLE campaign_contacts (
    campaign_id INTEGER NOT NULL,
    contact_id  INTEGER NOT NULL,
    sent_at     TEXT DEFAULT (datetime('now')), account_id INTEGER,
    UNIQUE(campaign_id, contact_id)
);
CREATE TABLE campaign_kps (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    campaign_id INTEGER NOT NULL,
    name        TEXT,                          -- тип/сегмент: «Застройщики», «Брокеры», «АН»
    when_to_use TEXT,                          -- условие выбора для агента: кому это КП подходит
    kp_text     TEXT,                          -- текст КП
    kp_file     TEXT,                          -- имя файла КП (в data/kp), опц.
    created_at  TEXT DEFAULT (datetime('now'))
);

