CREATE TABLE org_members (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    department_id INTEGER NOT NULL REFERENCES departments(id),
    kind          TEXT DEFAULT 'human',     -- human | agent
    name          TEXT,                     -- для human; для agent можно пусто (берём из ai_agents.name)
    role          TEXT,                     -- должность/роль
    phone         TEXT,
    email         TEXT,
    ai_agent_id   INTEGER REFERENCES ai_agents(id),  -- для kind='agent'
    needs_access  INTEGER DEFAULT 0,        -- нужен ли доступ в пульт (пока просто пометка на будущее)
    notes         TEXT,
    sort_order    INTEGER DEFAULT 0,
    created_at    TEXT DEFAULT (datetime('now'))
, account_id INTEGER, task TEXT, prompt TEXT);
Твоя задача: выходить на агентства недвижимости и договариваться о встрече (КЭВ).

Правила ведения диалога:
1. Первое касание — коротко, по делу: кто ты, откуда, что предлагаешь
2. После ответа — поддерживай диалог, отвечай на вопросы
3. Цель — назначить Zoom-встречу на 20 минут
4. Если не отвечают 5+ дней — одно вежливое напоминание
5. Никакого спама, не больше 2 сообщений без ответа
6. Тон — деловой, дружелюбный, уважительный

Ключевое предложение: помогаем агентствам закрывать сорвавшиеся сделки с ипотекой — выдаём заём под залог недвижимости, когда банк отказал. Быстро, до 20 млн, под 18% годовых.');
CREATE TABLE pipelines (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    name        TEXT,
    product     TEXT,
    project_id  INTEGER,
    stages      TEXT,                       -- JSON: [{"key":"new","label":"Новые"}, ...]
    is_default  INTEGER DEFAULT 0,
    created_at  TEXT DEFAULT (datetime('now'))
);
CREATE TABLE projects (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    name        TEXT,
    entity      TEXT,                       -- юр. сущность / бренд проекта
    description TEXT,
    status      TEXT DEFAULT 'active',      -- active|paused|done
    created_at  TEXT DEFAULT (datetime('now'))
);
CREATE TABLE proxies (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    kind        TEXT DEFAULT 'mtproto',     -- mtproto | socks5
    server      TEXT,
    port        INTEGER,
    secret      TEXT,
    ping_ms     INTEGER,                    -- TCP-пинг до сервера (мс), NULL = не проверен/мёртв
    status      TEXT DEFAULT 'new',         -- new | alive | dead
    source      TEXT,                       -- откуда (@канал)
    assigned_to INTEGER,                    -- accounts.id, если выдан аккаунту
    checked_at  TEXT,
    added_at    TEXT DEFAULT (datetime('now')),
    UNIQUE(server, port, secret)
);
CREATE TABLE tg_user_posts (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
