INSERT INTO "chats" VALUES(2027,'Обсуждаем ЖК БЕЛЫЕ ПЕСКИ | Скадовск','chat_belie_peski','https://t.me/chat_belie_peski','супергруппа',320,'~4 сообщений/день','analyzed',9,'Недвижимость',NULL,'2026-07-15 09:42:50','2026-07-12 20:22:17','не вступил','нет','yes','Скадовск',1643,1,2813196154,'закрыт','нет','Чат будущих жителей и покупателей квартир в ЖК «Белые Пески» в Скадовске. Обсуждаются строительство, планировки, приемка квартир и текущие вопросы.
