INSERT INTO "chats" VALUES(2029,'Спартанская Миля | Краснодар',NULL,'https://t.me/+8FEyluBWFVk2ZjEy','супергруппа',1009,'~26 сообщений/день','joined',9314,'спорт/фитнес',NULL,'2026-07-15 17:08:52','2026-07-12 20:22:17','да','да','yes','Краснодар',61325,1,1464454898,'открыт','да','Чат для любителей бега, фитнеса и тренировок. Участники делятся отчетами о тренировках, обсуждают спортивные события и поддерживают друг друга.
INSERT INTO "chats" VALUES(2030,'Досуг с Улыбкой','DosygSylibkoi','https://t.me/DosygSylibkoi','супергруппа',1223,'~7 сообщений/день','analyzed',NULL,'мероприятия/досуг',NULL,'2026-07-15 09:41:48','2026-07-12 20:22:17','нужно одобрение','нет',NULL,'Сочи',22165,1,1438447940,'закрыт','нет','Чат анонсирует мероприятия в Сочи: футбол, пикники, праздники, вечеринки. Аудитория — местные жители и туристы.
INSERT INTO "chats" VALUES(2031,'Оскар Хартманн','Oskar_Hartmann','https://t.me/Oskar_Hartmann','канал',93634,'~87 сообщений/день','analyzed',13,'бизнес',NULL,'2026-07-15 09:42:47','2026-07-12 20:22:17','только админы','нет','yes',NULL,NULL,1,1369973729,'скрыт','нет','Чат для обсуждения бизнес-идей, лидерства, найма и роли ИИ. Аудитория — предприниматели и интересующиеся бизнесом, есть общение с автором канала Оскаром Хартманном.
INSERT INTO "chats" VALUES(2032,'Маштаб - Сочи','Mashtab_Sochi','https://t.me/Mashtab_Sochi','супергруппа',3472,'~7 сообщений/день','joined',13,'нетворкинг',NULL,'2026-07-15 09:42:13','2026-07-12 20:22:17','только админы','да','yes','Сочи',17898,1,2350119781,'открыт','да','Чат сообщества предпринимателей и активных людей в Сочи. Основные активности — нетворкинг-встречи, деловые завтраки, мероприятия с баней, пикниками и выступлениями спикеров. Также присутствуют рекламные посты и объявления об оплате.
INSERT INTO "chats" VALUES(2033,'Комитет Строителей и Транспорта Сочи.','KomitetStroiSochiTPP','https://t.me/KomitetStroiSochiTPP','супергруппа',57,'~1 сообщений/день','analyzed',NULL,'строительство и бизнес',NULL,'2026-07-15 23:13:51','2026-07-12 20:22:17','нужно одобрение','нет',NULL,'Сочи',390,1,3462580109,'закрыт','нет','Чат Комитета Строителей и Транспорта при ТПП Сочи. Участники — предприниматели, застройщики, подрядчики. Обсуждают заседания, семинары, совместные проекты, услуги и заказы в строительстве и транспорте.
INSERT INTO "chats" VALUES(2034,'Бизнес Сириус | Адлер | Сочи','sirius_biznes','https://t.me/sirius_biznes','супергруппа',1006,'~3 сообщений/день','analyzed',NULL,'бизнес/нетворкинг',NULL,'2026-07-15 23:13:44','2026-07-12 20:22:17','нужно одобрение','нет',NULL,'Сириус/Адлер/Сочи',8615,1,1610191665,'закрыт','нет','Чат предпринимателей и активных жителей Сириуса/Адлера/Сочи: анонсы бизнес-встреч, нетворкинг, мероприятия (баня, экскурсии, девичники), поиск партнёров и услуг.
INSERT INTO "chats" VALUES(2035,'💌Интервью | чат / комментарии','LevchenkoStepanChat','https://t.me/LevchenkoStepanChat','супергруппа',1981,'~2 сообщений/день','analyzed',NULL,'бизнес, предпринимательство, маркетинг',NULL,'2026-07-15 23:13:31','2026-07-12 20:22:17','нужно одобрение','нет',NULL,'Москва',4557,1,2008129943,'закрыт','нет','Чат для комментариев к серии бизнес-интервью с предпринимателями на мероприятиях, конференциях и выставках. Однако в чате почти нет обсуждений — в основном пересылаются ссылки на интервью из канала.
