INSERT INTO "contacts" VALUES(1,'2gis','+78622645111','bersanorayana',678875382,'Винсент Недвижимость','Сочи','Винсент Недвижимость','Агентства недвижимости','http://www.vincent-realty.ru | https://vk.com/vincent_sochi | Несебрская улица, 6 к1 | Досье: Винсент Недвижимость, Сочи — агентство недвижимости в курортном регионе. Контактное лицо не определено, есть сайт, VK и Telegram. Сайт недоступен, специализация уточняется (вероятно курортная/инвестиционная недвижимость). | Досье: Винсент Недвижимость (Сочи), ООО, гендиректор Филиппов Эдуард Николаевич. Курортная/инвестиционная недвижимость, активны в VK и Telegram, сайт недоступен. | Досье: Винсент Недвижимость (Сочи), ООО, гендиректор Филиппов Эдуард Николаевич. Крупное агентство по элитной/курортной и инвестиционной недвижимости, широкая линейка услуг, активны в VK и Telegram, телефон 8-800.',NULL,'telegram','yes','unknown','unknown','2026-06-21 00:44:16','met','2026-06-15 23:26:04','2026-07-15 19:23:55','Филиппов Эдуард Николаевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Новостройки и элитная/курортная недвижимость Сочи (квартиры, пентхаусы, коттеджи), инвестиции, аренда, коммерция; юр. и ипотечные услуги','Эдуард Николаевич, у вас на сайте десятки элитных лотов от 50 до 340 млн и форма «Получить консультацию» — ИИ-бот может мгновенно квалифицировать заявку, подобрать объект по бюджету/району и не терять обращения из VK и Telegram, пока менеджеры на показах.',NULL,'2026-06-21 01:23:48','2320126581','1052311673622',NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(2,'2gis','+78622960703',NULL,NULL,'Оникс-Недвижимость','Сочи','Оникс-Недвижимость','Агентства недвижимости','http://onyx-realty.ru | https://vk.com/onyxrealty2012 | Навагинская улица, 3/4 | Досье: Оникс-Недвижимость — одно из крупнейших АН Сочи, гендиректор Демьяненко А.М. Полный спектр сделок + ипотека/инвестиции, акция на иногородних покупателей, несколько каналов входящих заявок — хороший фит под ИИ-квалификацию лидов и автоответы.','+79882360607','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-15 23:26:04','2026-07-15 19:23:55','Демьяненко Андрей Михайлович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Жилая и коммерческая недвижимость Сочи: новостройки, вторичка, дома/таунхаусы, участки; плюс ипотека, инвестиции, девелопмент. Работают и по Анапе/Крыму.','Андрей Михайлович, у вас широкая воронка по Сочи, Анапе и Крыму с акцией «Переезд за наш счёт» — на таком потоке заявок ИИ-бот может мгновенно квалифицировать иногородних покупателей и фиксировать брони 24/7, не теряя ночные обращения с горячей линии 8-800.',NULL,'2026-06-21 01:27:29','2320199815','1122366001625',NULL,NULL,NULL,NULL,2,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(3,'2gis','+79628859997',NULL,NULL,'Моравия','Сочи','Моравия','Агентства недвижимости','http://de-so.ru/deso-proekt | Курортный проспект, 96г к1 | Досье: ООО «Моравия», директор Невзорова Анна Владимировна. Агентство недвижимости в Сочи (Курортный проспект, 96г), ОКВЭД 68.10, статус активен. Сайт недоступен — зацепка на основе сезонного потока заявок по курортной недвижимости.','+79628859997','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-15 23:26:04','2026-07-15 19:23:55','Невзорова Анна Владимировна','ДИРЕКТОР','Элитная и курортная недвижимость Сочи (покупка/продажа)','Анна Владимировна, в сезон в Сочи поток заявок на курортные объекты на Курортном проспекте резко растёт — мы помогаем агентствам ИИ-ботом мгновенно отвечать и квалифицировать лиды 24/7, чтобы ни один покупатель не уходил к конкурентам.',NULL,'2026-06-21 01:27:45','2320253822','1172375106826',NULL,NULL,NULL,NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(4,'2gis','+78622777900',NULL,NULL,'Элитный Сочи','Сочи','Элитный Сочи','Агентства недвижимости','http://www.elitesochi.com/ | https://vk.com/elite_sochi_realty | Пластунская улица, 70 | Досье: ООО «Элитный Сочи» (ИНН 2320219067), гендиректор Заремба Роман Анатольевич. Агентство элитной недвижимости в Сочи, работа с иногородними клиентами, база 15 000+ квартир, услуги оплачивает застройщик. Воронка завязана на быстрый перезвон и подбор вариантов — потенциал для автоматизации квалификации и обработки заявок. | Досье: ООО «Элитный Сочи», гендиректор Заремба Роман Анатольевич. Элитная недвижимость для иногородних, база 15 000+ квартир, оплата от застройщика. Воронка завязана на быстрый перезвон и подбор — высокий потенциал для автоматизации квалификации и обработки заявок.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:11:48','2026-07-15 19:23:55','Заремба Роман Анатольевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Элитные новостройки и квартиры в Сочи для иногородних покупателей, услуги оплачивает застройщик','У вас обещан перезвон по заявке за 15 минут — ИИ-бот может квалифицировать иногородних лидов и отправлять подборку мгновенно 24/7, чтобы менеджер не терял горячих клиентов в нерабочее время.',NULL,'2026-06-21 01:29:25','2320219067','1142366002899',NULL,NULL,NULL,NULL,4,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(5,'2gis','+78002220501',NULL,NULL,'Лето','Сочи','Лето','Агентства недвижимости','http://leto-realty.ru | https://vk.com/letorealty | Кооперативная улица, 8 | Досье: АН «Лето» (ООО «Лето», ИНН 2317054048), Сочи, 10 лет на рынке, 400+ сотрудников, работают по Сочи/Крыму/ОАЭ/Турции с новостройками, элиткой и инвестициями. Руководители: Топалова Е.Ф. (ген.директор по ЕГРЮЛ) и Евгений Кривотулов (ген.директор по сайту).','+79384520070','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:11:48','2026-07-15 19:23:55','Топалова Елена Федоровна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Новостройки и инвестиционная недвижимость Сочи, элитка с видом на море, зарубеж (ОАЭ, Турция), дистанционные сделки, ипотека','У вас 400 сотрудников и 1450 объектов в базе, при этом средний выход новичка на первую сделку — 25 дней: ИИ-бот может квалифицировать входящие заявки и греть их в первые дни, разгружая риелторов от рутины и ускоряя путь к сделке.',NULL,'2026-06-21 01:28:07','2317054048','1092367002419',NULL,NULL,'общались на конференции, обещал перезвонить',NULL,5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(6,'2gis','+78001007191',NULL,NULL,'Городской Риэлторский Центр','Сочи','Городской Риэлторский Центр','Агентства недвижимости','info@grc-sochi.ru | http://grc-sochi.ru | https://vk.com/grcenter_sochi | улица Горького, 42/2 | Досье: ООО «Городской Риэлторский Центр», Сочи, ИНН 2320098253, активно. Руководитель — Усачева Юлия Игоревна (ген. директор). Риелторские услуги (ОКВЭД 68.31). Сайт недоступен, есть VK и email. Курортный регион — высокий поток входящих заявок.','+79628810052','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-15 19:23:55','Усачева Юлия Игоревна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Агентство недвижимости в Сочи (риелторские услуги, операции с недвижимостью, ОКВЭД 68.31). Вероятный фокус — курортная и инвестиционная недвижимость Сочи.','Юлия Игоревна, в Сочи у агентств всегда поток заявок от приезжих и инвесторов — настроим ИИ-бота, который сам отвечает на запросы по объектам 24/7 и квалифицирует лидов, чтобы ваши риелторы не тонули в рутине переписки.',NULL,'2026-06-21 01:28:23','2320098253','1022302919572',NULL,NULL,NULL,NULL,6,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(7,'2gis','+79311093555','rostsochi',NULL,'Рост недвижимость','Сочи','Рост недвижимость','Агентства недвижимости','http://rost-sochi.ru | https://vk.com/rostsochi | улица Орджоникидзе, 4Б | Досье: АН «Рост Недвижимость» (Сочи), гендиректор Майборода Евгений Викторович. Позиционируют себя как топ-агентство (23% рынка), фокус на новостройки и инвест-апартаменты премиум-класса; заявки идут через квиз и формы на сайте.',NULL,'telegram','yes','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-15 19:23:55','Майборода Евгений Викторович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','новостройки и элитная/инвестиционная недвижимость Сочи (апартаменты в премиальных ЖК, Красная Поляна, береговая линия)','Евгений Викторович, у вас огромная база объектов и поток заявок через квиз на сайте — ИИ-бот может квалифицировать лиды по типу недвижимости и бюджету 24/7 и отдавать риелторам только горячих, как Елизавете, разгрузив их от рутины.',NULL,'2026-06-21 01:28:33','2320239137','1162366053409',NULL,NULL,NULL,NULL,7,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(8,'2gis','+78002010303',NULL,NULL,'Атлас Недвижимость','Сочи','Атлас Недвижимость','Агентства недвижимости','http://atlas-realty.ru | https://vk.com/atlas.realty.sochi | Советская улица, 48 | Досье: Атлас Недвижимость (Сочи), гендиректор Антонов Антон Георгиевич. Многопрофильное агентство: элитка/бизнес/комфорт, ЖК, коттеджи, коммерция, участки, плюс консалтинг, ипотека, срочный выкуп, юруслуги. Большой поток входящих заявок через сайт-каталог и колл-центр — потенциал для ИИ-квалификации и автообработки лидов.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-15 19:23:55','Антонов Антон Георгиевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Элитная и инвестиционная недвижимость в Сочи (квартиры, дома, ЖК, коммерция, участки) + консалтинг и юруслуги','Антон Георгиевич, у вас широкая воронка по Сочи — от квартир до инвестпроектов и срочного выкупа, и через сайт и 8-800 наверняка идёт поток заявок; ИИ-бот мог бы мгновенно квалифицировать их по району/классу/бюджету и не терять лиды в нерабочее время.',NULL,'2026-06-21 01:28:44','2366022105','1202300041272',NULL,NULL,NULL,NULL,8,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(9,'2gis','+78002220944','oazisestate',NULL,'Oazis Estate Сочи','Сочи','Oazis Estate Сочи','Агентства недвижимости','http://t.me/oazisestate | улица 20 Горнострелковой Дивизии, 18а | Досье: Oazis Estate (Сочи) — агентство курортной недвижимости юга России, фокус на инвестиции. Активный Telegram-канал на 6,2к подписчиков, основной канал контакта @oazisestate. | Досье: Oazis Estate (Сочи) — агентство курортной недвижимости юга России с фокусом на инвестиции. Основной канал контакта — Telegram @oazisestate, 6,2к подписчиков, контактное лицо не указано.','+79388712193','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-15 19:23:55',NULL,NULL,'Курортная недвижимость юга России, инвестиции в метры','У вас активный Telegram на 6,2к подписчиков — наверняка в личку @oazisestate сыпется поток однотипных вопросов про объекты и цены; ИИ-бот может мгновенно квалифицировать эти заявки и отдавать вам только горячих инвесторов.',NULL,'2026-06-21 01:34:32',NULL,NULL,NULL,NULL,NULL,NULL,9,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(10,'2gis','+79384438259',NULL,NULL,'Этажи','Туапсе','Этажи','Агентства недвижимости','http://sochi.etagi.com | https://vk.com/etagi.realty | Привокзальная площадь, 1в | Досье: Федеральная франшиза Этажи в Туапсе/Сочи, на рынке с 2000 г., широкий профиль и большой поток заявок (сайт, vk, телефон). Делают упор на скорость перезвона и ИТ — хороший кандидат на автоматизацию обработки и квалификации заявок.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-15 19:23:55',NULL,NULL,'Полный цикл: новостройки, вторичка, дома/участки, аренда, коммерция, ипотека (федеральная франшиза Этажи)','Вы обещаете перезвон по заявке за 5 минут — наш ИИ-бот ловит каждую заявку с сайта и vk 24/7 и квалифицирует её до того, как риелтор возьмёт трубку, чтобы ни один лид не остыл.',NULL,'2026-06-21 01:29:04',NULL,NULL,NULL,NULL,NULL,NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(11,'2gis','+78005505120',NULL,NULL,'Лови Момент','Сочи','Лови Момент','Агентства недвижимости','улица Молокова, 44 | Досье: Агентство недвижимости ''Лови Момент'', Сочи (ул. Молокова, 44). Сайт недоступен, контактное лицо не определено. Вероятная специализация — курортная/инвестиционная недвижимость и новостройки Сочи.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-15 19:23:55',NULL,NULL,'Недвижимость в Сочи, вероятно новостройки и курортная/инвестиционная недвижимость','В Сочи поток заявок на курортные новостройки часто идёт круглосуточно — бот для мгновенного ответа на заявки с Авито/ВК и квалификации лидов поможет не терять горячих покупателей, пока менеджеры заняты.',NULL,'2026-06-21 01:29:10',NULL,NULL,NULL,NULL,NULL,NULL,11,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(12,'2gis','+78622644445',NULL,NULL,'Лидер','Сочи','Лидер','Агентства недвижимости','http://www.lidersochi.com | Несебрская улица, 4 | Досье: АН «Лидер» (Сочи), на рынке с 2012, 8000+ сделок, фокус на новостройки/инвестиции/ипотеку. Руководитель — Белова Марина Васильевна. Есть формы заявок, отдел продаж (рук. Мамедов Руслан) — рутина обработки лидов автоматизируема.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-15 19:23:55','Белова Марина Васильевна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Новостройки и инвестиции в недвижимость Сочи, ипотека, полный цикл купли-продажи','У вас более 8000 сделок и поток заявок с сайта/8-800 — ИИ-бот может мгновенно квалифицировать каждую заявку на подбор и не терять лиды, пока специалисты на показах.',NULL,'2026-06-21 01:29:20','2366026075','1212300012902',NULL,NULL,NULL,NULL,12,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(13,'2gis','+79384594000',NULL,8203176770,'ЖК Моравия','Сочи','ЖК Моравия','Агентства недвижимости,кампания #2','http://sochimoravia.ru/?utm_source=2gis&utm_medium=maps | Курортный проспект, 96г | Досье: Официальный отдел продаж ЖК «Моравия» (Сочи, Курортный пр-т 96г) — апартаменты бизнес-класса от 10 млн, 80+ лотов, продажа+аренда+коммерция. Высокий поток входящих заявок через WhatsApp/формы и отдельная партнёрка с агентами — хорошая база для ИИ-автоматизации обработки лидов.',NULL,'telegram','yes','unknown','unknown','2026-06-21 00:44:16','messaged','2026-06-21 00:44:16','2026-07-20 06:59:18',NULL,NULL,'Продажа и аренда апартаментов в премиальном апарт-комплексе бизнес-класса (новостройка от застройщика), Сочи','У вас на сайте идёт активный сбор заявок через WhatsApp и форму на каталог, плюс отдельный поток партнёров-агентов — могу показать, как ИИ-бот будет мгновенно отвечать в WhatsApp 24/7, квалифицировать клиента и сразу отправлять PDF-каталог с ценами, чтобы ни одна горячая заявка с курортного трафика не остывала.',NULL,'2026-06-21 01:29:30',NULL,NULL,NULL,NULL,NULL,NULL,13,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(14,'2gis','+79667757010',NULL,824211131,'Эталон недвижимость','Сочи','Эталон недвижимость','Агентства недвижимости,кампания #5','http://etalonrealty.ru | https://vk.com/etalonrealty_ru | улица Орджоникидзе, 18 | Досье: Эталон Недвижимость, Сочи, на рынке с 2010 (14 лет). Широкий спектр услуг и большой поток заявок на один телефон без онлайн-фильтрации — узкое место в обработке входящих, кандидат на ИИ-квалификацию лидов и снятие рутины.','+79667757010','telegram','yes','yes','unknown','2026-06-21 00:44:16','messaged','2026-06-21 00:44:16','2026-07-20 07:02:33',NULL,NULL,'Недвижимость Сочи полного цикла: новостройки от застройщика, вторичка, коттеджи/элитка, доверительное управление (аренда), плюс ремонт и строительство под ключ','У вас на сайте 7 услуг и единый номер +7 966 775-70-10 на все заявки в режиме «звонки в любое время» — ИИ-бот может квалифицировать обращения по новостройкам/вторичке/аренде и не терять лиды, пока менеджер на показе.',NULL,'2026-06-21 01:29:40',NULL,NULL,NULL,NULL,NULL,NULL,14,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(15,'2gis','+79384440412','reception_imperia',NULL,'Империя','Сочи','Империя','Агентства недвижимости','http://imperia-sochi.com | https://vk.com/imperia_sochi_nedvizhimost | Московская улица, 3 к5 | Досье: ГК «Империя» (Сочи), гендиректор Владимиров Евгений Владимирович. Крупное агентство новостроек по ФЗ-214, коттеджи, ипотека, строительный отдел и офис в Дубае (150+ специалистов). Много точек входа заявок — потенциал для ИИ-автоматизации квалификации и подбора.','+79384440412','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Владимиров Евгений Владимирович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Новостройки Сочи (ФЗ-214), коттеджи/таунхаусы, ипотека; есть строительный отдел (ремонт/дизайн) и офис в Дубае','Евгений Владимирович, у вас идёт поток заявок через формы на сайте и Telegram-ресепшн — ИИ-бот может мгновенно квалифицировать обращения по новостройкам Сочи и Дубая, отправлять подборки объектов и не терять лиды в нерабочее время.',NULL,'2026-06-21 01:29:50','0274188227','1140280037204',NULL,NULL,NULL,NULL,15,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(16,'2gis','+78007009265','domril',NULL,'Сан Пик','Сочи','Сан Пик','Агентства недвижимости','http://sunpiksochi.ru | https://vk.com/domril | улица Защитников Кавказа, 120/17 | Досье: Агентство в Сочи (ул. Защитников Кавказа, 120/17), специализируется на курортной инвестиционной недвижимости — апарт-отель Sun Peak на Красной Поляне по ценам застройщика. Контакты: тел. +7 966 770 58 25, TG @domril, vk.com/domril.','+79654750350','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-20 07:00:35',NULL,NULL,'Курортная инвестиционная недвижимость — апарт-отели/новостройки на Красной Поляне (комплекс Sun Peak), официальные цены застройщика','Видел, что Сан Пик продаёт апартаменты Sun Peak на Красной Поляне по ценам застройщика — у вас наверняка много заявок от инвесторов из других городов; ИИ-бот мог бы мгновенно отвечать на вопросы по планировкам и ценам и квалифицировать их, пока менеджер занят.',NULL,'2026-06-21 01:30:01',NULL,NULL,NULL,NULL,NULL,NULL,16,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(17,'2gis','+79885045439','sochi_in_live',NULL,'ProStore','Сочи','ProStore','Агентства недвижимости','http://prostore-sochi.ru | https://vk.com/prostore_realty | Московская улица, 3 к3 | Досье: ProStore (Сочи) — агентство по новостройкам, апартаментам и инвестиционной недвижимости с большим каталогом ГК/АК/ЖК по нескольким регионам. Контактное лицо не указано; точки входа — формы заявок и обещание перезвона за 5 минут.','+79885045439','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-20 07:00:37',NULL,NULL,'Новостройки, апартаменты и инвестиционная недвижимость (ГК/АК/ЖК) в Сочи, Крыму, Анапе, Архызе; продажа по ценам застройщика, инвестиции с расчётом окупаемости','У вас на сайте обещание «перезвоним в течение 5 минут» — ИИ-бот может квалифицировать и мгновенно отвечать на заявки по сотням ЖК/АК круглосуточно, чтобы ни один лид по горящим предложениям не остывал.',NULL,'2026-06-21 01:30:10',NULL,NULL,NULL,NULL,NULL,NULL,17,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(18,'2gis','+79005554455',NULL,5703154800,'Аска недвижимость','Сочи','Аска недвижимость','Агентства недвижимости,кампания #2','http://aska-realty.ru | https://vk.com/askarealty_sochi | улица Конституции СССР, 4 | Досье: Аска недвижимость (Сочи), агентство №1 по самопозиционированию, гендиректор Каратеев А.С. Широкий профиль: новостройки, элитка, апартаменты, инвестпроекты, направления Геленджик и Дубай. Активные онлайн-каналы (сайт, VK, WhatsApp, Telegram) — высокий поток заявок, потенциал для ИИ-автоматизации обработки лидов и подборок.','+79005554455','telegram','yes','yes','unknown','2026-06-21 00:44:16','messaged','2026-06-21 00:44:16','2026-07-20 07:00:39','Каратеев Александр Сергеевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Полный спектр недвижимости Сочи: новостройки бизнес-класса, элитка, апартаменты, инвестпроекты (окупаемость до 46%), а также Геленджик и Дубай','Александр Сергеевич, у вас огромный каталог по Сочи, Геленджику и Дубаю плюс десятки районов — менеджеры наверняка тонут в одинаковых заявках ''получить презентацию ЖК'', можем повесить на ИИ-бота моментальную выдачу подборок и квалификацию по бюджету/району.',NULL,'2026-06-21 01:30:22','2320185812','1102366007028',NULL,NULL,NULL,NULL,18,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(19,'2gis','+79288502701',NULL,NULL,'Polivanov plus','Сочи','Polivanov plus','Агентства недвижимости','http://polivanov-plus.ru | https://vk.com/club211051952 | Московская улица, 22 | Досье: Агентство недвижимости в Сочи (Московская, 22), специализируется на новостройках, апартаментах и элитных виллах с упором на удалённые сделки и ипотеку (одобрение 95%). Контактного лица в данных нет, заявки идут через форму и мессенджеры — точка роста для ИИ-автоматизации обработки лидов.','+79288502701','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-20 07:00:45',NULL,NULL,'Новостройки и элитная загородная недвижимость в Сочи (ЖК, апарт-отели, виллы), ипотечное сопровождение, работа с иногородними клиентами','Вы работаете с иногородними удалённо и обещаете ответ в течение часа — ИИ-бот мог бы мгновенно квалифицировать заявки из формы и мессенджеров 24/7, чтобы ни один клиент из другого города не ждал и не уходил к конкуренту.',NULL,'2026-06-21 01:30:32',NULL,NULL,NULL,NULL,NULL,NULL,19,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(20,'2gis','+79631634921',NULL,5344089920,'Аякс','Сочи','Аякс','Агентства недвижимости,кампания #2','http://ayax.ru | https://vk.com/ayax.realty | Навагинская улица, 13 | Досье: Аякс — крупное универсальное агентство недвижимости (Краснодар, офис в Сочи), полный цикл сделок + ипотека/оценка/аренда, статусы ''Супер агентство'' Циан/Яндекс. Внимание: юрлицо ООО ''АЯКС'' (ИНН 0274128309) в статусе LIQUIDATED, руководитель — ликвидатор Гальченко Д.В.; перед контактом проверить актуальное действующее юрлицо/бренд.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','messaged','2026-06-21 00:44:16','2026-07-20 07:00:47','Гальченко Дмитрий Владимирович','Ликвидатор','Полный цикл сделок с жильём (новостройки, вторичка, дома, участки, коммерция), плюс ипотека, оценка, аренда — крупное универсальное агентство в Краснодаре/Сочи','Вы держите статус «Супер агентство» от Циан и работаете по всему циклу — купля, продажа, ипотека, аренда: при таком потоке заявок ИИ-бот может первым отвечать на звонки/заявки по объектам 24/7 и квалифицировать клиентов до риелтора, чтобы менеджеры не тонули в рутине.',NULL,'2026-06-21 01:30:44','0274128309','1080274003556',NULL,NULL,NULL,NULL,20,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(21,'2gis','+79282087063',NULL,7020385309,'Buro','Сочи','Buro','Агентства недвижимости,кампания #2','http://t.me/burosochi | https://vk.com/burosochi | Навагинская улица, 13 к1 | Досье: Buro (ООО ''Бюро'', Сочи) — инвестиционная недвижимость, отбор проектов под вложения. Руководитель Емельчева Юлия Сергеевна, активна в Telegram (@burosochi, 416 подписчиков) и ВК. Точка боли — ручная обработка заявок инвесторов.','+79282087063','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','messaged','2026-06-21 00:44:16','2026-07-20 07:00:55','Емельчева Юлия Сергеевна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','инвестиционная недвижимость в Сочи (объекты под вложения)','Юлия, у вас в Telegram-канале ''проекты, в которые вложились бы сами'' — а сколько входящих заявок от инвесторов вы сейчас обрабатываете вручную, не теряя горячих в потоке?',NULL,'2026-06-21 01:30:52','2367032709','1232300048067',NULL,NULL,NULL,NULL,21,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(22,'2gis','+78622967777','more_nedvizhimost',NULL,'Море Недвижимость','Сочи','Море Недвижимость','Агентства недвижимости','http://more-realty.ru | https://vk.com/more_nedvizhimost | улица Войкова, 1/1 | Досье: «Море Недвижимость» (Сочи, Войкова 1/1) — агентство полного цикла с 10+ лет опыта, 5000+ сделок, широкий портфель: новостройки, элитка, загородка, коммерция, инвестпроекты, работа с иностранцами. Контактное лицо не указано, выходить через общие каналы (тел/Telegram/VK).','+79667790500','telegram','yes','yes','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-20 07:01:10',NULL,NULL,'Новостройки Сочи и побережья, инвестиции, элитка, загородная (коттеджи/таунхаусы), коммерция — сопровождение сделок под ключ, работа с инвесторами и иностранцами','У вас 2 номера + Telegram + VK и сотни объектов от новостроек до элитных КП за 65 млн — поток входящих заявок огромный; ИИ-бот может мгновенно квалифицировать лида по бюджету/району/классу и не терять обращения в нерабочее время, хотя у вас график до 20:00.',NULL,'2026-06-21 01:31:03',NULL,NULL,NULL,NULL,NULL,NULL,22,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(23,'2gis','+79587702437',NULL,NULL,'Lekhto group','Сочи','Lekhto group','Агентства недвижимости','http://t.me/lekhtonedvig | https://vk.com/lekhtogroup | Кубанская улица, 15 | Досье: Сочинское агентство курортной инвестнедвижимости, работает по Сочи/Крыму/Архызу/Алтаю через Telegram (3.2к подписчиков) и VK. Лиды идут на одного менеджера — есть риск потери заявок, точка входа для автоматизации квалификации.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-20 07:01:11',NULL,NULL,'Инвестиционная курортная недвижимость (Сочи, Крым, Архыз, Алтай), закрытые лоты и VIP-эксклюзивы','У вас Telegram-канал на 3194 подписчика и связь только через @lekhtogroup_manager — ИИ-бот мог бы мгновенно квалифицировать заявки на закрытые лоты и не терять инвесторов, пока менеджер занят.',NULL,'2026-06-21 01:31:12',NULL,NULL,NULL,NULL,NULL,NULL,23,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(24,'2gis','+79399996108',NULL,NULL,'Integrity','Сочи','Integrity','Агентства недвижимости','http://integrity-estate.ru | Водораздельная улица, 5 | Досье: Агентство Integrity (Сочи, Водораздельная ул., 5), сайт integrity-estate.ru недоступен. Контактное лицо не определено. Профиль — недвижимость Сочи, вероятно курортная/инвестиционная.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-20 07:01:11',NULL,NULL,'Недвижимость Сочи — вероятно новостройки и курортная/инвестиционная недвижимость','В Сочи поток заявок на курортные новостройки идёт нон-стоп — настроим ИИ-бота, который мгновенно отвечает и квалифицирует лидов 24/7, чтобы вы не теряли горячих клиентов из-за задержки ответа.',NULL,'2026-06-21 01:31:27',NULL,NULL,NULL,NULL,NULL,NULL,24,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(25,'2gis','+78624444800',NULL,NULL,'Сова','Сочи','Сова','Агентства недвижимости','http://sova72.ru | https://vk.com/sova72.rielt | улица Лазарева, 90а | Досье: АН СОВА (Сочи, ул. Лазарева 90а) — крупное универсальное агентство с огромной базой объектов и множеством каналов заявок. Контактное лицо не указано, есть телефон 8(862)4444-800 и vk. Боль: ручная обработка большого потока заявок.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','lost','2026-06-21 00:44:16','2026-07-20 07:01:11',NULL,NULL,'Широкопрофильное АН в Сочи: новостройки, вторичка, дома/участки, коммерция, аренда (в т.ч. посуточная), ипотека; большой объём объектов','У вас на сайте тысячи объектов (1378 студий, 4054 квартир без комиссии) и формы заявок по покупке/обмену/аренде — ИИ-бот может мгновенно квалифицировать каждую заявку и подбирать объекты, чтобы риелторы не тонули в рутине обработки.',NULL,'2026-06-21 01:31:49',NULL,NULL,NULL,NULL,NULL,NULL,25,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(26,'2gis','+79388678888','nebo_realty',NULL,'Небо недвижимость','Сочи','Небо недвижимость','Агентства недвижимости','http://nebo-realty.ru | https://vk.com/neborealty | Тоннельная улица, 2Б | Досье: Небо Недвижимость (Сочи), ген. директор Евгений Павленко. Специализация — новостройки, апартаменты и коттеджи Сочи, инвестанализ. Активно собирают заявки через формы-квизы с обещанием ответа за 3 минуты — есть рутина по квалификации лидов под автоматизацию.','+79388678888','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Павленко Евгений Валерьевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','новостройки Сочи (ЖК, апарт-комплексы, коттеджные поселки), инвестиции, подбор и продажа','У вас на сайте обещание перезвонить и прислать подборку за 3 минуты — ИИ-бот может мгновенно квалифицировать заявки по типу/бюджету/срокам и закрывать эти 3 минуты даже ночью, чтобы ни один лид из VK и форм не остыл.',NULL,'2026-06-21 01:32:00','2366025410','1212300006247',NULL,NULL,NULL,NULL,26,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
