INSERT INTO "contacts" VALUES(32,'2gis','+78002220429',NULL,NULL,'Ривьера','Сочи','Ривьера','Агентства недвижимости','http://riverasochi.ru | https://vk.com/riviera__sochi | улица 20 Горнострелковой Дивизии, 18а | Досье: Агентство недвижимости Ривьера в Сочи, специализируется на вторичном рынке. Директор Гончаров Д.И. — точка принятия решений по автоматизации процессов обработки заявок.','+79181009006','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Гончаров Дмитрий Иванович','ДИРЕКТОР','недвижимость, вторичка','Гончаров, видим, что в Ривьере обрабатывают запросы клиентов вручную — покажем, как боты берут на себя квалификацию и первичный контакт, чтобы вашей команде осталось только закрытие сделок.',NULL,'2026-07-14 19:02:43','2320166094','1082366001156',NULL,NULL,NULL,NULL,32,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
