INSERT INTO "contacts" VALUES(36,'2gis','+78007003261',NULL,NULL,'Новостройки Групп','Сочи','Новостройки Групп','Агентства недвижимости','http://novostroykasochi.ru | https://vk.com/dvizhka_club | Курортный проспект, 73 | Досье: ООО «Новостройки Групп» — лидирующее агентство новостроек в Сочи, работает с первичным рынком (ФЗ-214, ипотека). Генерирует клиентов через сайт и соцсети, нуждается в снятии рутины обработки входящих заявок.','+79053099551','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Галяутдинов Азамат Алифович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','новостройки','У вас большой поток первичных заявок с сайта и VK — автоматизируем их распределение между агентами и квалификацию прямо в CRM.',NULL,'2026-07-14 19:02:42','2367043926','1252300049121',NULL,NULL,NULL,NULL,36,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
