INSERT INTO "contacts" VALUES(60,'2gis','+74958462261',NULL,NULL,'Перспектива','Сочи','Перспектива','Агентства недвижимости','http://perspektiva-crimea.ru/?utm_campaign=2gis&utm_medium=cpv&utm_source=2gis | https://vk.com/perspektiva_crimea | Московская улица, 3 к5 | Досье: Девелопер недвижимости в Крыму, специализируется на жилых инвестициях и арендном бизнесе. Активно принимает заявки через сайт и мессенджеры, требует автоматизации обработки лидов.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Данилин Денис Юрьевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Девелопмент и продажа курортной недвижимости в Крыму (новостройки, инвестиции, аренда)','Обработка 50+ входящих заявок в месяц через один бот — экономия 15 часов работы менеджера в неделю только на первичной квалификации.',NULL,'2026-07-14 19:02:41','7802717500','1107847194300',NULL,NULL,NULL,NULL,60,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
