INSERT INTO "contacts" VALUES(62,'2gis','+78003008333',NULL,NULL,'Глобал инвест групп','Сочи','Глобал инвест групп','Агентства недвижимости','Кипарисовая улица, 4 | Досье: Глобал Инвест Групп (Сочи), гендиректор Наринянц Анна Николаевна, ОКВЭД 68.31 — агентство недвижимости с уклоном в инвестиции. Сайт недоступен, контакты ограничены адресом.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Наринянц Анна Николаевна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','недвижимость Сочи, вероятно инвестиции и новостройки (название + ОКВЭД 68.31)','Анна Николаевна, в Сочи поток заявок на инвест-объекты обычно идёт нон-стоп — настроим ИИ-бота, который мгновенно квалифицирует лидов из всех каналов и не теряет горячих клиентов в пик сезона.',NULL,'2026-06-21 01:31:25','2366034830','1222300016730',NULL,NULL,NULL,NULL,62,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
