INSERT INTO "contacts" VALUES(70,'2gis','+79183066656',NULL,NULL,'Алмаз-Юг','Сочи','Алмаз-Юг','Агентства недвижимости','http://almaz-yug.ru | Навагинская улица, 3/15 | Досье: Агентство недвижимости в Сочи, специализация на вторичном рынке и элитных объектах. Компания ликвидирована по статусу ЕГРЮЛ (проверить актуальность контактов).','+79183066656','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Титов Антон Михайлович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Вторичка, элитка в Сочи','Заметил, что ваше агентство работает с премиум-сегментом на Навагинской — у таких клиентов высокие требования к скорости обработки запросов, а это требует автоматизации.',NULL,'2026-07-14 19:02:34','2320127151','1052311676163',NULL,NULL,NULL,NULL,70,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(71,'2gis','+78007004567',NULL,NULL,'АльянсЪ','Сочи','АльянсЪ','Агентства недвижимости','http://www.an-alyans.ru | https://vk.com/alyans.rielt | Депутатская улица, 9/3 | Досье: ООО «АльянсЪ» — агентство недвижимости в Сочи с широким портфелем (квартиры, коттеджи, новостройки разных ценовых сегментов). Руководитель Сергей Иванович Гаврилов. Компания закрыта, но контакты актуальны.','+79884102277','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Гаврилов Сергей Иванович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Вторичка, новостройки, элит-класс','В Сочи агентства теряют 40% времени на обработку звонков и заявок — а у вас их явно много, судя по двум номерам отдела продаж.',NULL,'2026-07-14 19:02:43','2319057069','1142367010961',NULL,NULL,NULL,NULL,71,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(72,'2gis','+79189065356','bazikyan',NULL,'Инвест Сочи','Сочи','Инвест Сочи','Агентства недвижимости','https://vk.com/investsochiru | Виноградная улица, 204Б/1 | Досье: Инвест Сочи — агентство инвестиционной недвижимости, специализирующееся на продаже объектов недвижимости в Сочи. Руководитель Артур Агекян. Есть потенциал автоматизации обработки входящих заявок от инвесторов.','+79189065356','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Агекян Артур Ерджаникович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','инвестиционная недвижимость, продажа объектов в Сочи','Артур, в вашем агентстве ежедневно обрабатываются заявки от инвесторов — мы помогли аналогичным агентствам в Сочи снизить время ответа клиентам с 4 часов до 15 минут через ИИ-бота.',NULL,'2026-07-14 19:02:44','2367041421','1252300010863',NULL,NULL,NULL,NULL,72,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
