INSERT INTO "contacts" VALUES(176,'2gis','+79388780400',NULL,NULL,'Эра Недвижимости','Сочи','Эра Недвижимости','Агентства недвижимости','http://t.me/eranedvizhimosti | Армавирская улица, 20а к3 | Досье: ООО «Эра Недвижимости», Сочи. Занимаются покупкой/продажей/арендой, специализируются на новостройках. Есть Telegram-канал, но нет видимой автоматизации процессов привлечения клиентов.','+79388780400','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Агаев Александр Сергеевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Вторичка/аренда/новостройки Сочи','В Telegram-канале 178 подписчиков, но через бота можно автоматизировать подбор квартир и обработку заявок — освободит время на закрытие сделок вместо ручных ответов.',NULL,'2026-07-14 19:02:39','2366049026','1242300030884',NULL,NULL,NULL,NULL,176,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(177,'2gis','+79884124290','svetlanashifanova',NULL,'Агентство недвижимости','Сочи','Агентство недвижимости','Агентства недвижимости','http://arenda-vsochi.ru | https://vk.com/club225679531 | Армавирская улица, 20а к3 | Досье: ООО «Агентство недвижимости Лазурный Сочи» специализируется на доверительном управлении квартирами и апартаментами, посуточной и долгосрочной аренде в Сочи. Берут на себя полный цикл: уборку, ремонт, хоумстейджинг, размещение на множество платформ и работу с арендаторами 24/7.','+79601856225','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Кузнецова Эвелина Александровна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Доверительное управление недвижимостью и посуточная аренда','Вижу, что вы вручную управляете всем — от уборки и ремонта до размещения на 30+ площадках и заселения гостей — хотите автоматизировать хотя бы обработку заявок и уведомления?',NULL,'2026-07-14 19:02:34','2367037993','1242300032644',NULL,NULL,NULL,NULL,177,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(178,'2gis','+79881572727',NULL,NULL,'Валькирия','Сочи','Валькирия','Агентства недвижимости','Звёздная улица, 18а | Досье: ООО «Валькирия» — агентство недвижимости в Сочи под руководством Алины Мироненко. Специализируется на продаже и сдаче в аренду жилых объектов на вторичном рынке. Хороший кандидат для автоматизации обработки клиентских запросов и квалификации лидов через ИИ-бота.','+79881572727','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Мироненко Алина Константиновна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Агентство недвижимости (вторичка, Сочи)','Алина, в вашем агентстве каждый день уходит время на повторяющиеся задачи с заявками — мы помогли аналогичным агентствам в Сочи экономить на этом 15+ часов в неделю.',NULL,'2026-07-14 19:02:38','2320198057','1112366013594',NULL,NULL,NULL,NULL,178,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(179,'2gis','+79937710023',NULL,NULL,'Оливия','Сочи','Оливия','Агентства недвижимости','http://zkolivia.ru | улица Ленина, 290/7а | Досье: ООО ''Оливия'' — девелоперское агентство в Сочи, специализирующееся на продажах в новом жилом комплексе премиум-класса. Генеральный директор Гунин С.В. может сэкономить время команды на обработке входящих запросов и квалификации инвесторов через автоматизацию.','+79937710023','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Гунин Сергей Васильевич','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Новостройки, инвестиции в недвижимость','В Оливии продают квартиры в премиум-комплексе в 700м от моря — вероятно, ежедневно десятки звонков от потенциальных инвесторов, которые теряются в потоке заявок.',NULL,'2026-07-14 19:02:42','2366032760','1212300071235',NULL,NULL,NULL,NULL,179,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(180,'2gis','+79659907810',NULL,NULL,'Дом Курорт','Сочи','Дом Курорт','Агентства недвижимости','http://t.me/beka_sova_o | https://vk.com/bekas_ova | Лучезарная улица, 1а к3 | Досье: МБУК «Дом культуры «Юбилейный» в Сочи. Директор Осокина О.В. Учреждение культуры, потенциально нуждается в автоматизации бронирований и обработки заявок.','+79659907810','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Осокина Ольга Валериевна','ДИРЕКТОР','Учреждение культуры (ДК)','Автоматизируем обработку заявок на аренду помещений и мероприятия — освобождаете время для клиентов вместо бумажной работы.',NULL,'2026-07-14 19:02:44','2320094876','1022302960393',NULL,NULL,NULL,NULL,180,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(181,'2gis','+79882392221',NULL,NULL,'Лучезарный','Сочи','Лучезарный','Агентства недвижимости','Лучезарная улица, 1а | Досье: НАО «Пансионат Лучезарный» (Сочи). Генерального директор Сергей Минасян. Основной вид деятельности — услуги проживания в пансионатах. Потенциал автоматизации в обработке заявок бронирования и входящих звонков.','+79882392221','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Минасян Сергей Меликович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','гостинично-туристический комплекс с услугами размещения','Сергей, заметил, что «Лучезарный» принимает много гостей — вероятно, много звонков и бронирований, которые обрабатываются вручную?',NULL,'2026-07-14 19:02:44','2318029534','1032310485371',NULL,NULL,NULL,NULL,181,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(182,'2gis','+79683001957',NULL,NULL,'Хостинский отдых','Сочи','Хостинский отдых','Агентства недвижимости','Платановая улица, 41а | Досье: ООО «Хостинский отдых», Сочи. Специализируется на аренде недвижимости. Директор Медведева Ф.Ф. Потенциал для автоматизации обработки заявок и коммуникаций с клиентами.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Медведева Феня Федоровна','ДИРЕКТОР','Аренда недвижимости','Феня, вижу, что «Хостинский отдых» работает с арендой в Сочи — сколько заявок в день обрабатываете вручную?',NULL,'2026-07-14 19:02:41','2319023101','1022302831100',NULL,NULL,NULL,NULL,182,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(183,'2gis','+79882371686',NULL,NULL,'Офис продаж','Сочи','Офис продаж','Агентства недвижимости','Сухумское шоссе, 7/2 | Досье: Офис продаж на Сухумском шоссе, работает с жилой недвижимостью (вторичка). Потенциал автоматизации предквалификации и распределения заявок.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55',NULL,NULL,'вторичка, жилая недвижимость в Сочи','Боты в Telegram и WhatsApp забирают 80% звонков по квартирам — ваши агенты могли бы заниматься только горячими клиентами.',NULL,'2026-07-14 19:02:35',NULL,NULL,NULL,NULL,NULL,NULL,183,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(184,'2gis','+78622968501',NULL,NULL,'Лето','Сочи','Лето','Агентства недвижимости','http://leto-realty.ru | https://vk.com/letorealty | Старонасыпная улица, 22 | Досье: ООО «Лето» — крупное агентство недвижимости в Сочи, специализирующееся на премиум-сегменте, новостройках и инвестиционных проектах. Под руководством Елены Топаловой работает с портфелем объектов в ОАЭ и на черноморском побережье.','+79384520070','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Топалова Елена Федоровна','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Новостройки и вторичное жилье, инвестиции в недвижимость, премиум-сегмент','Елена, заметил, что в вашем портфеле много новостроек с длительными сроками сдачи — автоматизация обработки заявок могла бы сократить время отклика на 80% и конвертировать больше потенциальных инвесторов.',NULL,'2026-07-14 19:02:43','2317054048','1092367002419',NULL,NULL,NULL,NULL,184,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(185,'2gis','+79284522121',NULL,NULL,'Дом недвижимости','Сочи','Дом недвижимости','Агентства недвижимости','улица Декабристов, 20/5 | Досье: ООО «Любимый дом» — агентство недвижимости во вторичном сегменте Сочи. Руководитель Марина Мельникова. Потенциал для автоматизации обработки клиентских обращений и квалификации лидов через ИИ-боты.','+79882350532','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Мельникова Марина Сергеевна','ДИРЕКТОР','вторичка','В Сочи агентства теряют 30-40% заявок на обработку — автоматизация входящих запросов вернёт вам эти сделки.',NULL,'2026-07-14 19:02:42','2367014393','1202300031230',NULL,NULL,NULL,NULL,185,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(186,'2gis','+79180023455',NULL,NULL,'У моря','Сочи','У моря','Агентства недвижимости','http://in-sochi.com | https://vk.com/olivir | улица Декабристов, 59а | Досье: Агентство У моря работает с загородной недвижимостью и участками в районе Сочи (Лоо, Дагомыс, Якорная Щель и др.). Позиционируют себя как альтернативу традиционным риэлторам — может быть болью обработка однотипных заявок на сайте и звонки.','+79180023455','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Барадуля Наталья Анатольевна','ПРЕДСЕДАТЕЛЬ','Загородная недвижимость и земельные участки в Сочи','Вижу, что вы специализируетесь на премиум загородной недвижимости в окрестностях Сочи — заметил портфель объектов от 2 до 35 млн, скорее всего много звонков с одинаковыми вопросами о наличии и характеристиках.',NULL,'2026-07-14 19:02:35','2319059884','1152367005449',NULL,NULL,NULL,NULL,186,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(187,'2gis','+79777001070',NULL,NULL,'Авангард','Туапсе','Авангард','Агентства недвижимости','http://tuapse-avangard.ru | Победы, 10 | Досье: ООО «Строительная компания Авангард», руководитель Чиликов Д.А. Агентство недвижимости в Туапсе. Специализация на вторичном рынке и новостройках.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Чиликов Денис Александрович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Вторичка, новостройки','Денис, в Туапсе растёт спрос на квартиры — а обработка звонков и заявок всё ещё ручная?',NULL,'2026-07-14 19:02:40','2365018628','1112365001671',NULL,NULL,NULL,NULL,187,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(188,'2gis','+79286679115',NULL,NULL,'Вавилон','Сочи','Вавилон','Агентства недвижимости','улица Ленина, 60 | Досье: ООО «Вавилон» — агентство недвижимости в Сочи. Директор Арам Оксузян. Потенциал автоматизации: обработка клиентских заявок, распределение между агентами, первичные консультации через чат-бота.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Оксузян Арам Меликович','ДИРЕКТОР','недвижимость','Арам, у вас в Сочи агентство получает заявки — но сколько из них теряется в переписке и звонках?',NULL,'2026-07-14 19:02:43','2317022053','1022302722342',NULL,NULL,NULL,NULL,188,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
