INSERT INTO "contacts" VALUES(190,'2gis','+79384413090',NULL,NULL,'Курорт','Сочи','Курорт','Агентства недвижимости','улица Просвещения, 198 | Досье: ООО «Бальнеологический курорт «Мацеста» — агентство в Сочи, специализирующееся на курортной и загородной недвижимости. Руководитель Аллан Асланович Мамишев. Потенциал: автоматизация обработки заявок через ИИ.','+79384413090','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Мамишев Аллан Асланович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','курортная недвижимость, загородная недвижимость','Мамишев, у вас же в Мацесте постоянный поток клиентов, ищущих апартаменты на сезон — почему бы не автоматизировать первичный скрининг заявок через бота и сэкономить два часа в день менеджеру?',NULL,'2026-07-14 19:02:39','2319026342','1022302831583',NULL,NULL,NULL,NULL,190,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(191,'2gis','+79178325410',NULL,NULL,'А+','Сочи','А+','Агентства недвижимости','http://complex-flora-sochi.ru | улица Искры, 66/9 | Досье: А+ — агентство недвижимости в Сочи под управлением Омельченко А.А. Работает на вторичном рынке. Нуждается в автоматизации обработки клиентских заявок.','+79178325410','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Омельченко Андрей Александрович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Агентство недвижимости, вторичное жилье','Андрей, в Сочи агентства теряют 30% времени на обработку заявок — можно автоматизировать распределение лидов и первичную квалификацию через бота.',NULL,'2026-07-14 19:02:39','2367026310','1222300038840',NULL,NULL,NULL,NULL,191,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
