INSERT INTO "contacts" VALUES(210,'2gis','+79186153896','housewithpool',NULL,'Сочи квартал','Сочи','Сочи квартал','Агентства недвижимости','http://домсбассейном.рф | Кирпичная улица, 24 блок Б | Досье: Агентство «Сочи квартал» специализируется на новостройках и инвестициях в недвижимость Сочи. Директор Чуков Д.В. Сайт использует интерактивные квизы для сбора заявок, но требует автоматизации их обработки.','+79186153896','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Чуков Дмитрий Викторович','ДИРЕКТОР','Новостройки, апартаменты, инвестиции в недвижимость Сочи','У вас в каталоге десятки объектов, а заявки обрабатываются вручную — боты могли бы квалифицировать покупателей и отправлять горячие лиды за 30 секунд вместо часов.',NULL,'2026-07-14 19:02:44','2319035555','1052311092756',NULL,NULL,NULL,NULL,210,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(211,'2gis','+79384412723',NULL,NULL,'Flagman','Сочи','Flagman','Агентства недвижимости','улица Мира, 42 | Досье: ООО «Флагман» — агентство недвижимости в Сочи. Руководитель Титовец С.А. Специализируется на продаже вторичного жилья.','+79384412723','telegram','yes','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Титовец Сергей Александрович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Агентство недвижимости, вторичка','Сочинское агентство теряет 15-20% заявок на квартиры из-за медленного ответа — внедрим бота для мгновенной обработки запросов и квалификации покупателей',NULL,'2026-07-14 19:02:35','2366018518','1202300001606',NULL,NULL,NULL,NULL,211,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(212,'2gis','+79882331137',NULL,NULL,'Maxbase','Сочи','Maxbase','Агентства недвижимости','http://max-base.ru | улица Конституции СССР, 4 | Досье: Maxbase — агентство недвижимости в Сочи. Сайт неактивен (проблема с доменом). Можем автоматизировать приём заявок через WhatsApp/Telegram и обработку клиентских запросов, пока сайт восстанавливается или параллельно с ним.','+79882396042','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55',NULL,NULL,'Агентство недвижимости (вторичное жильё, покупка-продажа)','Ваш сайт не работает — домен требует продления, но это же означает, что потенциальные клиенты теряются в момент поиска квартир.',NULL,'2026-07-14 19:02:41',NULL,NULL,NULL,NULL,NULL,NULL,212,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(213,'2gis','+79778158455',NULL,NULL,'Yarent','Сочи','Yarent','Агентства недвижимости','http://ярент.рф | https://vk.com/netassett | Водораздельная улица, 5/1 | Досье: ООО управляющая компания Yarent в Сочи, специализируется на доверительном управлении и сдаче квартир. Руководитель Макаров А.А. Есть потенциал для ИИ-автоматизации обработки лидов и коммуникаций с клиентами.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Макаров Антон Александрович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Управление недвижимостью, аренда квартир','Yarent ежемесячно обрабатывает десятки заявок от арендаторов — можно автоматизировать всю цепочку: скрининг, ответы, назначение просмотров.',NULL,'2026-07-14 19:02:42','2367030758','1232300024813',NULL,NULL,NULL,NULL,213,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
