INSERT INTO "contacts" VALUES(217,'2gis','+79996563689',NULL,NULL,'Sk123',NULL,'Sk123','Агентства недвижимости','http://t.me/alfa_construction | https://vk.com/s.k_123 | Старообрядческая улица, 62 | Досье: СК Регион 123 — строительное агентство (ОКВЭД 41.20) с фокусом на новостройки. Основной канал коммуникации — Telegram. Руководитель Кириенко Н.А.','+79996563689','whatsapp','unknown','yes','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55','Кириенко Наталья Александровна','ДИРЕКТОР','новостройки','Видю, что основной канал клиентов — Telegram. Могу автоматизировать квалификацию заявок в боте, чтобы ваши менеджеры работали только с горячими.',NULL,'2026-07-14 19:02:43','0100008412','1240100001239',NULL,NULL,NULL,NULL,217,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
