INSERT INTO "contacts" VALUES(220,'2gis','+74959884777',NULL,NULL,'R Seven Group','Сочи','R Seven Group','Агентства недвижимости','http://r7-group.ru/ | Старонасыпная улица, 22 | Досье: Управляющая компания, специализирующаяся на коммерческом управлении и аренде недвижимости в Сочи и других городах. Активно принимает заявки через сайт.',NULL,'telegram','unknown','unknown','unknown','2026-06-21 00:44:16','new','2026-06-21 00:44:16','2026-07-15 19:23:55',NULL,NULL,'управление коммерческой недвижимостью, аренда помещений','В R Seven Group ежедневно теряются часы на обработку заявок от потенциальных арендаторов — пора это автоматизировать.',NULL,'2026-07-14 19:02:38',NULL,NULL,NULL,NULL,NULL,NULL,220,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
