INSERT INTO "contacts" VALUES(295,'тест','+79881678180','Neiro_0001',6724617319,'Неометрия','Сочи','Неометрия (застройщик)','тест,кампания #3','Тест-контакт кампании Фонда | Досье: Агентство недвижимости в Сочи. Тестируют маркетинговые кампании. Потенциал в автоматизации обработки заявок и снятии рутины с менеджеров.',NULL,'telegram','yes','no','unknown',NULL,'meeting_set','2026-06-21 18:54:02','2026-07-15 19:23:55',NULL,NULL,'недвижимость','Видим, что Неометрия активно тестирует новые каналы привлечения клиентов — можем автоматизировать обработку заявок из них через ИИ-бота.',NULL,'2026-07-14 19:02:41',NULL,NULL,NULL,NULL,NULL,NULL,295,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(296,'тест','+79137876067','neiro_1000',8468498628,'Велес Васильевич','Сочи','Велес — частный ипотечный брокер','тест,ИЖС,test_kev,кампания #9003,кампания #2,кампания #9404','Тест-контакт кампании Фонда | Досье: ООО «Велес», директор Легезин В.В., Сочи. Компания в процессе ликвидации — критичное время для оптимизации процессов и сохранения клиентской базы.',NULL,'telegram','yes','yes','unknown',NULL,'new','2026-06-21 18:54:02','2026-07-20 19:57:24','Легезин Владимир Васильевич','ДИРЕКТОР','вторичный рынок','Видим, что «Велес» закрывается — помогаем агентствам перед ликвидацией автоматизировать обработку заявок, чтобы не потерять сделки в переходном периоде.',NULL,'2026-07-14 19:02:35','2320175613','1092366005269',NULL,NULL,NULL,NULL,296,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'другое',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(297,'тест','+77027417272',NULL,1918803222,'АН Алматы','Алматы','Агентство недвижимости Алматы','тест,ИЖС,кампания #3,test_kev,кампания #9003,кампания #2,кампания #9404','Тест-контакт кампании Фонда | Досье: АН Алматы Рил Эстейт — агентство недвижимости. Данные ограничены (тест-контакт), специализация не уточнена. Потенциал внедрения автоматизации обработки входящих заявок от клиентов.',NULL,'telegram','yes','yes','unknown',NULL,'new','2026-06-21 18:54:02','2026-07-20 19:57:24',NULL,NULL,'общее агентство недвижимости','Боты в Telegram и WhatsApp сокращают время обработки заявок в 3 раза — протестируем на вашем потоке клиентов?',NULL,'2026-06-25 10:36:10',NULL,NULL,NULL,NULL,NULL,NULL,297,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(301,'tg_parse',NULL,'vugrinchuk',480864022,'Анастасия Вугринчук | LASH BOSS',NULL,NULL,'TG-парсинг: @biznesdvigsochi / активный','Найден парсером TG в @biznesdvigsochi (активный) | Досье: Владелица топовой школы обучения лэш-мастеров, активно ищет каналы привлечения клиентов и рекламных возможностей. Ориентирована на рост и видимость в нише. | Досье: Владелица школы обучения лэш-мастеров LASH BOSS. Активно развивает бизнес, ищет каналы привлечения клиентов и работает в соцсетях.',NULL,'telegram','yes','unknown','unknown',NULL,'new','2026-06-25 17:09:57','2026-07-15 19:24:44','Анастасия Вугринчук','Владелица','Образование в сфере красоты (обучение лэш-мастеров)','Школа красоты, которая растёт в соцсетях — значит, готовы автоматизировать обработку заявок и не терять клиентов в Telegram','💐 Владелица №1 школы Lash мастеров в РФ и СНГ clck.ru/3ATFq7 Мои бьюти чаты @top_beauty_masters @lashboss_club @beauty_boss_club','2026-07-14 19:02:42',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Управление школой и масштабирование бизнеса, поиск платных рекламных каналов, привлечение клиентов','','Развивать лидирующую позицию на рынке обучения лэш-мастеров, масштабировать школу, привлекать внимание целевой аудитории','Бизнес; маркетинг; красота/lash-индустрия; нетворкинг; реклама; школы обучения','Предприниматель-статусник, ориентирована на рост и видимость','Прямая, деловая, по делу. Использует инструментальный тон. На ''вы''. Короткие фразы, без лирики.','Дневное время (сообщения в деловой чат днём)',0.75,'красота/бьюти','реклама платная, по рекламе ко мне | Владелица №1 школы Lash мастеров в РФ и СНГ','Анастасия, видю, что масштабируете школу через рекламу — у нас есть решение для быстрого привлечения мастеров с гарантией ROI. Хотите разберём?',NULL,0.65,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(302,'tg_parse',NULL,'medvedev_blog',82947866,'Валерий | Автоворонки | MBA маркетолог',NULL,NULL,'TG-парсинг: @biznesdvigsochi / активный','Найден парсером TG в @biznesdvigsochi (активный) | Досье: MBA маркетолог из Сочи, создающий высокоэффективные автоворонки для инфобизнеса (ROI 1:5). Прямой, ориентирован на результат, активно продвигает своё предложение в профессиональных сообществах. | Досье: Валерий — MBA маркетолог из Сочи, специалист по высокоэффективным автоворонкам для инфобизнеса (ROI 1:5). Активен в профессиональных сообществах, ориентирован на результат.',NULL,'telegram','yes','unknown','unknown',NULL,'new','2026-06-25 17:09:57','2026-07-15 19:24:44','Валерий','MBA маркетолог','автоворонки для инфобизнеса','Вижу, что вы создаёте воронки с ROI 1:5 — у агентств недвижимости похожая проблема: 80% звонков теряются до первого контакта, а квалификация клиентов идёт вручную.','Создаю автоворонки лидерам инфобиза с окупаемостью 1к5 на холодке. Бесплатный курс по автоворонкам, жми тут https://t.me/valeriimedvedev/802','2026-07-14 19:02:41',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Ограничения на продвижение в чатах, необходимость платить за рекламу, конкуренция в инфобизе','Блокировка аккаунтов, потеря доступа к каналам генерации лидов, неэффективные способы привлечения аудитории','Органический рост и лидогенерация, признание в профессиональном сообществе, масштабирование своего предложения','Автоворонки; инфобиз; маркетинг; лидогенерация; продажи; нетворкинг','Прямолинейный, операционно мыслящий, ориентирован на результат (ROI), немного агрессивный в коммуникации','Директивный, короткие факт-ориентированные фразы, на ''ты'', низкая толерантность к дебатам, быстрые решения','Дневное время (судя по активности в бизнес-чатах днём)',0.65,'маркетинг/реклама','Визитка - это самореклама. И спорить смысла нет | реклама платно, в след раз бан','Валерий, видал твои автоворонки для инфобизнеса — результаты 1:5 на холодке это серьёзно. Поговорим про масштабирование без ограничений платформ?',NULL,0.62,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(303,'tg_parse',NULL,'volt3',1311886870,'Юрий Leon',NULL,NULL,'TG-парсинг: @biznesdvigsochi / активный','Найден парсером TG в @biznesdvigsochi (активный) | Досье: Аналитик-предприниматель, который помогает стоматологам оптимизировать рекламу через воронки и экономику. Ищет специалистов для делегирования рутины. Активен в бизнес-сообществе Сочи. | Досье: ООО Макаров, руководит Юрий Макаров. Специализируется на оптимизации рекламных воронок для стоматологов и ищет способы автоматизации рутинных процессов.',NULL,'telegram','yes','unknown','unknown',NULL,'new','2026-06-25 17:09:57','2026-07-15 19:24:44','Макаров Юрий Леонидович','ГЕНЕРАЛЬНЫЙ ДИРЕКТОР','Оптимизация рекламы и воронок для стоматологов, делегирование рутины','Вижу, что вы помогаете стоматологам оптимизировать рекламу — наш бот справится с обработкой заявок и снимет рутину с вашей команды.',NULL,'2026-07-14 19:02:41','7000033746','1267000001949',NULL,NULL,NULL,NULL,NULL,'Рутинные задачи отвлекают от стратегии; неэффективная реклама и неоптимизированные воронки продаж приводят к потерям бюджета','','Найти специалиста, который возьмет на себя операционную работу; оптимизировать экономику бизнеса и рекламные расходы','Бизнес; маркетинг и директ; стоматология; экономика бизнеса; аналитика воронок','Рациональный, аналитический; ориентирован на метрики и результаты; проактивный советчик','Дружеский, профессиональный тон; открыт к обсуждению; предпочитает конкретные цифры и решения; отвечает развернуто с примерами','',0.75,'медицина/здоровье','Отдать специалисту рутину | в стоматологии это критично, ведь без экономики пациента и воронки любой Директ будет либо дорогим, либо убыточным | где именно сейчас теряются деньги','Юрий, вижу, что вы глубоко разбираетесь в экономике рекламы для стоматологии. Есть инструмент, который помогает директологам и владельцам клиник видеть утечки бюджета в реальном времени — может быть полезен для ваших клиентов?',NULL,0.65,NULL,0,NULL,NULL,0,NULL,NULL);
INSERT INTO "contacts" VALUES(304,'tg_parse',NULL,'evachernykh',160035367,'Евгения Черных',NULL,NULL,'TG-парсинг: @biznesdvigsochi / активный','Найден парсером TG в @biznesdvigsochi (активный) | Досье: ИП риэлтора Евгении Черных, активная в соцсетях. Подходит для внедрения ИИ-ботов для обработки заявок и автоматизации коммуникаций с клиентами.',NULL,'telegram','yes','unknown','unknown',NULL,'new','2026-06-25 17:09:57','2026-07-15 19:23:55','Черных Евгения Александровна','ИП','Риэлтор, работа с недвижимостью','Евгения, заметили вашу активность в @biznesdvigsochi — помогаем риэлторам Сочи автоматизировать обработку клиентских заявок через боты, чтобы не терять контакты','« Настоящая красота - это гармония формы и содержания, и содержание должно преобладать , а форма лишь служить ему » …','2026-07-14 19:02:40','290703184844','323290000001119',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'недвижимость',NULL,NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL);
